// chunk-core.mjs — pure, environment-agnostic helpers shared by the Par Avion
// browser app and its tests. No DOM, no Node-only APIs: only btoa/atob, which
// are global in both modern browsers and Node 18+. Keep it that way so the exact
// same code runs in the browser and under `node --test`.
//
// This file is the SOURCE OF TRUTH. The copy inlined inside par-avion/index.html
// (between the CHUNK-CORE markers) is generated by `npm run build`. Edit here,
// then run `npm run build` and `npm test`.

// Largest raw chunk whose base64-encoded email stays under the given byte limit.
// base64 expands ~4/3, a CRLF is added every 76 chars, and we reserve room for
// headers/MIME boundaries plus a safety margin for providers that count loosely.
export function rawChunkSizeForEmailLimit(emailLimitBytes) {
  const HEADER_OVERHEAD = 8 * 1024; // headers, body text, MIME boundaries
  const B64 = 4 / 3;                // base64 expansion
  const NEWLINE = 1 + 2 / 76;       // CRLF every 76 encoded chars
  const SAFETY = 0.92;              // headroom for provider quirks
  const usable = (emailLimitBytes - HEADER_OVERHEAD) * SAFETY;
  return Math.max(1, Math.floor(usable / (B64 * NEWLINE)));
}

// Uint8Array -> base64 string. Chunked so we never blow the call stack.
export function bytesToBase64(bytes) {
  let bin = '';
  const block = 0x8000;
  for (let i = 0; i < bytes.length; i += block) {
    bin += String.fromCharCode.apply(null, bytes.subarray(i, i + block));
  }
  return btoa(bin);
}

// base64 string -> Uint8Array.
export function base64ToBytes(b64) {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

// Wrap a base64 string at 76 chars per line (RFC 2045), CRLF-joined.
export function wrap76(b64) {
  const lines = [];
  for (let i = 0; i < b64.length; i += 76) lines.push(b64.slice(i, i + 76));
  return lines.join('\r\n');
}

// Build one single-part .eml draft. `boundary` is injected by the caller so this
// stays deterministic and environment-agnostic (the app passes a random one).
export function buildEml({ to, tag, origName, index, total, partName, b64wrapped, boundary }) {
  const subject = `${tag} [${index}/${total}] ${origName}`;
  const body =
`Part ${index} of ${total} of "${origName}".
Save this attachment, gather all ${total} parts, then reassemble them with Par Avion.`;
  return [
    to ? `To: ${to}` : `To: `,
    `Subject: ${subject}`,
    `X-ChunkMail-Original: ${origName}`,
    `X-ChunkMail-Part: ${index}/${total}`,
    `MIME-Version: 1.0`,
    `Content-Type: multipart/mixed; boundary="${boundary}"`,
    ``,
    `--${boundary}`,
    `Content-Type: text/plain; charset="utf-8"`,
    `Content-Transfer-Encoding: 7bit`,
    ``,
    body,
    ``,
    `--${boundary}`,
    `Content-Type: application/octet-stream; name="${partName}"`,
    `Content-Transfer-Encoding: base64`,
    `Content-Disposition: attachment; filename="${partName}"`,
    ``,
    b64wrapped,
    `--${boundary}--`,
    ``
  ].join('\r\n');
}

// Parse a part filename "name.ext.partNNNofMMM" -> { base, index, total } | null.
export function parsePartName(name) {
  const m = name.match(/^(.*)\.part(\d+)of(\d+)$/i);
  return m ? { base: m[1], index: +m[2], total: +m[3] } : null;
}

// Pull metadata + the attachment's base64 payload out of a .eml string.
// Returns { base, index, total, base64 } — base/index/total may be null if the
// X-ChunkMail headers are absent (caller can fall back to the filename).
export function parseEml(text) {
  const origM = text.match(/^X-ChunkMail-Original:\s*(.+)$/im);
  const partM = text.match(/^X-ChunkMail-Part:\s*(\d+)\/(\d+)/im);
  const octIdx = text.search(/Content-Type:\s*application\/octet-stream/i);
  if (octIdx < 0) return null;
  let s = text.indexOf('\r\n\r\n', octIdx);
  let off = 4;
  if (s < 0) { s = text.indexOf('\n\n', octIdx); off = 2; }
  if (s < 0) return null;
  const rest = text.slice(s + off);
  const endRel = rest.search(/\r?\n--/); // closing MIME boundary
  const b64 = rest.slice(0, endRel >= 0 ? endRel : undefined).replace(/\s+/g, '');
  return {
    base: origM ? origM[1].trim() : null,
    index: partM ? +partM[1] : null,
    total: partM ? +partM[2] : null,
    base64: b64
  };
}

// Zero-pad a part number to 3 digits.
export function padPart(n) {
  return String(n).padStart(3, '0');
}
